class LetterTile(BoxLayout):
    bg_color = ListProperty([1, 1, 1, 1])

    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self.label = Label(
            text="",
            font_size=24,
            bold=True,
            font_name="NotoHebrewBold",
            color=get_color_from_hex("#333333")
        )
        self.add_widget(self.label)
        self.bind(
            bg_color=self.update_canvas,
            pos=self.update_canvas,
            size=self.update_canvas
        )

    def update_canvas(self, *args):
        self.canvas.before.clear()
        with self.canvas.before:
            Color(rgba=[0, 0, 0, 0.25])
            RoundedRectangle(
                pos=(self.pos[0]+3, self.pos[1]-3),
                size=self.size, radius=[14]
            )
            Color(rgba=self.bg_color)
            RoundedRectangle(pos=self.pos, size=self.size, radius=[14])
            Color(rgba=[1, 1, 1, 0.35])
            RoundedRectangle(
                pos=(self.pos[0]+3, self.pos[1]+self.size[1]*0.55),
                size=(self.size[0]-6, self.size[1]*0.38),
                radius=[14]
            )
            Color(rgba=[0, 0, 0, 0.15])
            Line(rounded_rectangle=(
                self.pos[0]+1, self.pos[1]+1,
                self.size[0]-2, self.size[1]-2, 14
            ), width=1.5)

    def set_letter(self, letter, color=None, font_name="NotoHebrewBold"):
        self.label.text = letter.upper() if letter else ""
        self.label.font_name = font_name
        if color:
            self.bg_color = color
            self.label.color = [1, 1, 1, 1]
        else:
            self.bg_color = [1, 1, 1, 1]
            self.label.color = get_color_from_hex("#333333")

    def pop(self):
        pass

    def bounce(self):
        anim = Animation(opacity=0.5, duration=0.08) + \
               Animation(opacity=1.0, duration=0.08) + \
               Animation(opacity=0.7, duration=0.08) + \
               Animation(opacity=1.0, duration=0.08)
        anim.start(self)

