def make_button(text, bg_color, font_name="NotoHebrewBold", text_color=None, font_size=18):
    btn = Button(
        text=text,
        font_name=font_name,
        font_size=font_size,
        background_color=[0, 0, 0, 0],
        color=text_color or [1, 1, 1, 1],
        background_normal="",
        background_down=""
    )
    btn._bg_color = bg_color
    btn.bind(pos=lambda b, v: _update_btn_shadow(b),
             size=lambda b, v: _update_btn_shadow(b))
    return btn

def _update_btn_shadow(btn):
    btn.canvas.before.clear()
    with btn.canvas.before:
        Color(rgba=[0, 0, 0, 0.3])
        RoundedRectangle(pos=(btn.x+3, btn.y-3), size=btn.size, radius=[12])
        Color(rgba=btn._bg_color)
        RoundedRectangle(pos=btn.pos, size=btn.size, radius=[12])

