def build_keyboard_widget(parent, language, on_key, on_back, on_enter, enter_text="V", used_letters=None):
    kb = parent.ids.keyboard_area if hasattr(parent.ids, "keyboard_area") else parent.ids.setter_keyboard
    kb.clear_widgets()
    rows = [HE_ROW1, HE_ROW2, HE_ROW3] if language == "he" else EN_ROWS
    used_letters = used_letters or {}

    for i, row in enumerate(rows):
        row_layout = BoxLayout(spacing=4, size_hint_y=1)

        if i == len(rows) - 1:
            btn = make_button("X", get_color_from_hex("#BF360C"), font_size=22)
            btn.size_hint_x = 1.5
            btn.bind(on_press=lambda x: on_back())
            row_layout.add_widget(btn)

        for letter in row:
            status = used_letters.get(letter.lower() if letter.isascii() else letter, "unused")
            if status == "wrong":
                color = get_color_from_hex("#444444")
                txt_color = [0.6, 0.6, 0.6, 1]
            else:
                color = get_color_from_hex("#D3D6DA")
                txt_color = [0, 0, 0, 1]

            btn = make_button(letter, color, font_size=20, text_color=txt_color)
            btn.size_hint_x = 1
            letter_copy = letter
            btn.bind(on_press=lambda x, l=letter_copy: on_key(l))
            row_layout.add_widget(btn)

        if i == len(rows) - 1:
            btn = make_button(enter_text, get_color_from_hex("#1B5E20"), font_size=22)
            btn.size_hint_x = 1.5
            btn.bind(on_press=lambda x: on_enter())
            row_layout.add_widget(btn)

        kb.add_widget(row_layout)

