def build_tile_grid_widget(parent, num_rows=None):
    grid = parent.ids.tile_grid
    grid.clear_widgets()
    grid.rows = 1
    tiles = []
    # Start with just one empty row
    for _ in range(WORD_LENGTH):
        tile = LetterTile()
        tiles.append(tile)
