def update_row_display(tiles, current_row, guess, language, font):
    for col in range(WORD_LENGTH):
        index = current_row * WORD_LENGTH + col
        if index >= len(tiles):
            return
        if language == "he":
            right_index = current_row * WORD_LENGTH + (WORD_LENGTH - 1 - col)
            if right_index >= len(tiles):
                return
            tile = tiles[right_index]
            tile.set_letter(guess[col] if col < len(guess) else "", font_name=font)
        else:
            tiles[index].set_letter(guess[col] if col < len(guess) else "", font_name=font)

def color_row_display(tiles, current_row, guess, feedback, language, font):
    if language == "he":
        guess = guess[::-1]
        feedback = feedback[::-1]
    for col in range(len(guess)):
        index = current_row * WORD_LENGTH + col
        if index >= len(tiles):
            return
        tiles[index].set_letter(guess[col], COLORS[feedback[col]], font_name=font)

