class ModeScreen(Screen):
    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self.language = "en"

    def set_language(self, language):
        self.language = language

    def on_enter(self, *args):
        Clock.schedule_once(self._update_labels, 0.1)

    def _update_labels(self, dt):
        if not self.ids:
            return
        lang = self.language
        pairs = [
            ("title_label", t(lang, "word_game")),
            ("subtitle_label", t(lang, "choose_mode")),
            ("single_btn", t(lang, "single_player")),
            ("multi_btn", t(lang, "pass_play")),
            ("online_btn", t(lang, "play_online")),
            ("rules_btn", t(lang, "rules")),
            ("back_btn", t(lang, "back")),
        ]
        for widget_id, text in pairs:
            widget = getattr(self.ids, widget_id)
            widget.font_name = "NotoHebrewBold"
            widget.text = text

    def choose_mode(self, mode):
        if mode == "single":
            game_screen = self.manager.get_screen("game")
            game_screen.start_game(language=self.language, infinite=True)
            self.manager.current = "game"
        else:
            word_setter = self.manager.get_screen("word_setter")
            word_setter.request_setup(self.language)
            self.manager.current = "word_setter"

    def go_online(self):
        online_menu = self.manager.get_screen("online_menu")
        online_menu.set_language(self.language)
        self.manager.current = "online_menu"

    def go_rules(self):
        rules = self.manager.get_screen("rules")
        rules.set_language(self.language)
        self.manager.current = "rules"

