class OnlineMenuScreen(Screen):
    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self.language = "en"

    def set_language(self, language):
        self.language = language

    def on_enter(self, *args):
        lang = self.language
        self.ids.title_label.text = t(lang, "online_play")
        self.ids.title_label.font_name = "NotoHebrewBold"
        self.ids.subtitle_label.text = t(lang, "play_with_friend")
        self.ids.subtitle_label.font_name = "NotoHebrewBold"
        self.ids.create_btn.text = t(lang, "create_game")
        self.ids.create_btn.font_name = "NotoHebrewBold"
        self.ids.join_btn.text = t(lang, "join_game")
        self.ids.join_btn.font_name = "NotoHebrewBold"
        self.ids.back_btn.text = t(lang, "back")
        self.ids.back_btn.font_name = "NotoHebrewBold"

    def choose_online_mode(self, mode):
        if mode == "create":
            setter = self.manager.get_screen("online_setter")
            setter.setup(self.language)
            self.manager.current = "online_setter"
        else:
            join = self.manager.get_screen("online_join")
            join.setup(self.language)
            self.manager.current = "online_join"

