class OnlineSetterScreen(Screen):
    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self.language = "en"
        self.secret_word = ""
        self.game_code = ""

    def setup(self, language):
        self.language = language
        self.secret_word = ""

    def on_enter(self, *args):
        Clock.schedule_once(self._init, 0.1)

    def _init(self, dt):
        import threading
        self.ids.code_label.text = "..."
        lang = self.language
        def do_create():
            try:
                from online_game import create_game
                code = create_game(lang)
            except Exception as e:
                code = None
                err_msg = str(e)[:80]
                def show_err(dt, msg=err_msg):
                    self.ids.error_label.text = msg
                Clock.schedule_once(show_err, 0)
                return
            def on_done(dt):
                self.game_code = code if code else "ERR"
                self.ids.code_label.text = self.game_code
                self.ids.title_label.text = t(lang, "your_code")
                self.ids.title_label.font_name = "NotoHebrewBold"
                self.ids.share_label.text = t(lang, "share_code")
                self.ids.share_label.font_name = "NotoHebrewBold"
                self.ids.type_label.text = t(lang, "type_secret")
                self.ids.type_label.font_name = "NotoHebrewBold"
                self.secret_word = ""
                self.ids.hidden_display.text = "_ _ _ _ _"
                self.ids.error_label.text = ""
                self.ids.back_btn.text = t(lang, "back")
                self.ids.back_btn.font_name = "NotoHebrewBold"
                build_keyboard_widget(
                    self, lang,
                    self.on_key_press, self.on_backspace,
                    self.on_confirm, enter_text="V"
                )
            Clock.schedule_once(on_done, 0)
        threading.Thread(target=do_create, daemon=True).start()

    def on_key_press(self, letter):
        if len(self.secret_word) <= WORD_LENGTH - 1:
            self.secret_word += letter
            self._update_display()

    def on_backspace(self):
        if self.secret_word:
            self.secret_word = self.secret_word[:-1]
            self._update_display()

    def _update_display(self):
        count = len(self.secret_word)
        if self.language == "he":
            dots = "_ " * (WORD_LENGTH - count) + "\u25cf " * count
        else:
            dots = "\u25cf " * count + "_ " * (WORD_LENGTH - count)
        self.ids.hidden_display.text = dots.strip()

    def on_confirm(self):
        lang = self.language
        if len(self.secret_word) != WORD_LENGTH:
            self.ids.error_label.text = t(lang, "must_be_5")
            return
        if not is_valid_word_offline(self.secret_word, lang):
            self.ids.error_label.text = t(lang, "not_valid")
            return
        from online_game import set_word
        set_word(self.game_code, "p1", self.secret_word)
        game_screen = self.manager.get_screen("online_game")
        game_screen.setup(
            language=lang,
            game_code=self.game_code,
            role="p1",
            my_word=self.secret_word
        )
        self.manager.current = "online_game"

