class OnlineJoinScreen(Screen):
    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self.language = "en"
        self.code_input = ""

    def setup(self, language):
        self.language = language
        self.code_input = ""

    def on_enter(self, *args):
        lang = self.language
        self.code_input = ""
        self.ids.code_input_display.text = "____"
        self.ids.join_error_label.text = ""
        self.ids.title_label.text = t(lang, "join_game")
        self.ids.title_label.font_name = "NotoHebrewBold"
        self.ids.subtitle_label.text = t(lang, "enter_code")
        self.ids.subtitle_label.font_name = "NotoHebrewBold"
        self.ids.back_btn.text = t(lang, "back")
        self.ids.back_btn.font_name = "NotoHebrewBold"

    def on_digit(self, digit):
        if len(self.code_input) < 4:
            self.code_input += digit
            self.ids.code_input_display.text = self.code_input + "_" * (4 - len(self.code_input))

    def on_backspace(self):
        if self.code_input:
            self.code_input = self.code_input[:-1]
            self.ids.code_input_display.text = self.code_input + "_" * (4 - len(self.code_input))

    def on_join(self):
        lang = self.language
        if len(self.code_input) != 4:
            self.ids.join_error_label.text = t(lang, "enter_4digits")
            return
        from online_game import join_game
        game_data = join_game(self.code_input)
        if game_data is None:
            self.ids.join_error_label.text = t(lang, "game_not_found")
            return
        if game_data["status"] == "finished":
            self.ids.join_error_label.text = t(lang, "game_finished")
            return
        self.manager.get_screen("online_setter_p2").setup(
            language=game_data["language"],
            game_code=self.code_input
        )
        self.manager.current = "online_setter_p2"

