class RulesScreen(Screen):
    def __init__(self, **kwargs):
        super().__init__(**kwargs)
        self.language = "en"

    def set_language(self, language):
        self.language = language

    def on_enter(self, *args):
        Clock.schedule_once(self._update, 0.1)

    def _update(self, dt):
        lang = self.language
        if lang == "he":
            self.ids.rules_text.text = RULES_HE
            self.ids.rules_text.halign = "right"
        else:
            self.ids.rules_text.text = RULES_EN
            self.ids.rules_text.halign = "left"
        self.ids.rules_text.font_name = "NotoHebrewBold"
        self.ids.title_label.text = t(lang, "rules")
        self.ids.title_label.font_name = "NotoHebrewBold"
        self.ids.back_btn.text = t(lang, "back")
