class WordDuelApp(App):
    def build(self):
        sm = ScreenManager()
        sm.add_widget(MenuScreen(name="menu"))
        sm.add_widget(ModeScreen(name="mode_screen"))
        sm.add_widget(WordSetterScreen(name="word_setter"))
        sm.add_widget(PassPhoneScreen(name="pass_phone"))
        sm.add_widget(GameScreen(name="game"))
        sm.add_widget(OnlineMenuScreen(name="online_menu"))
        sm.add_widget(OnlineSetterScreen(name="online_setter"))
        sm.add_widget(OnlineJoinScreen(name="online_join"))
        sm.add_widget(OnlineSetterP2Screen(name="online_setter_p2"))
        sm.add_widget(OnlineGameScreen(name="online_game"))
        sm.add_widget(RulesScreen(name="rules"))
        return sm

